DROP TABLE IF EXISTS attendance, audit_logs, employees, municipalities, areas, supervisors, users, franchises CASCADE;

-- Kiosk Mapping V2 Merged Database Schema
-- Generated from backend schema, update, performance, and seed SQL files.
-- Run this single script in the Supabase SQL Editor for a fresh or existing project.

CREATE TABLE IF NOT EXISTS franchises (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    name VARCHAR(255) UNIQUE NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS users (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    email VARCHAR(255) UNIQUE NOT NULL,
    password_hash VARCHAR(255) NOT NULL,
    full_name VARCHAR(255) NOT NULL,
    role VARCHAR(50) DEFAULT 'staff',
    franchise_id BIGINT REFERENCES franchises(id),
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS supervisors (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    color VARCHAR(50) DEFAULT '#3b82f6',
    franchise_id BIGINT REFERENCES franchises(id),
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    UNIQUE(name, franchise_id)
);

CREATE TABLE IF NOT EXISTS areas (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    name VARCHAR(255) UNIQUE NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS municipalities (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    franchise_id BIGINT REFERENCES franchises(id),
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    UNIQUE(name, franchise_id)
);

CREATE TABLE IF NOT EXISTS employees (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    employee_id VARCHAR(50) UNIQUE NOT NULL,
    full_name VARCHAR(255) NOT NULL,
    supervisor_id BIGINT REFERENCES supervisors(id),
    role VARCHAR(100) NOT NULL,
    address TEXT,
    latitude DECIMAL(10, 8),
    longitude DECIMAL(11, 8),
    contact_number VARCHAR(50),
    franchise_id BIGINT REFERENCES franchises(id),
    area_id BIGINT REFERENCES areas(id),
    status VARCHAR(50) DEFAULT 'Active',
    radius_meters INTEGER DEFAULT 200,
    municipality_id BIGINT REFERENCES municipalities(id),
    photo_url TEXT,
    id_photo_url TEXT,
    coordinate_screenshot_url TEXT,
    qr_code TEXT,
    created_by BIGINT REFERENCES users(id),
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS audit_logs (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    user_id BIGINT REFERENCES users(id),
    action VARCHAR(50) NOT NULL,
    table_name VARCHAR(100) NOT NULL,
    record_id BIGINT,
    changes JSONB,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS attendance (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    employee_id BIGINT REFERENCES employees(id) ON DELETE CASCADE,
    scan_time TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    status VARCHAR(50) DEFAULT 'On Duty',
    latitude DECIMAL(10, 8),
    longitude DECIMAL(11, 8),
    distance_meters DECIMAL(10, 2),
    alert_type VARCHAR(50),
    remarks TEXT,
    scan_source VARCHAR(50),
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

ALTER TABLE employees ADD COLUMN IF NOT EXISTS contact_number VARCHAR(50);
ALTER TABLE employees ADD COLUMN IF NOT EXISTS radius_meters INTEGER DEFAULT 200;
ALTER TABLE employees ADD COLUMN IF NOT EXISTS municipality_id BIGINT REFERENCES municipalities(id);
ALTER TABLE employees ADD COLUMN IF NOT EXISTS photo_url TEXT;
ALTER TABLE employees ADD COLUMN IF NOT EXISTS id_photo_url TEXT;
ALTER TABLE employees ADD COLUMN IF NOT EXISTS coordinate_screenshot_url TEXT;
ALTER TABLE attendance ADD COLUMN IF NOT EXISTS scan_source VARCHAR(50);
ALTER TABLE users ADD COLUMN IF NOT EXISTS franchise_id BIGINT REFERENCES franchises(id);
ALTER TABLE supervisors ADD COLUMN IF NOT EXISTS franchise_id BIGINT REFERENCES franchises(id);
ALTER TABLE municipalities ADD COLUMN IF NOT EXISTS franchise_id BIGINT REFERENCES franchises(id);

ALTER TABLE supervisors DROP CONSTRAINT IF EXISTS supervisors_name_key;
ALTER TABLE municipalities DROP CONSTRAINT IF EXISTS municipalities_name_key;

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'supervisors_name_franchise_id_key'
    ) THEN
        ALTER TABLE supervisors ADD CONSTRAINT supervisors_name_franchise_id_key UNIQUE(name, franchise_id);
    END IF;

    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'municipalities_name_franchise_id_key'
    ) THEN
        ALTER TABLE municipalities ADD CONSTRAINT municipalities_name_franchise_id_key UNIQUE(name, franchise_id);
    END IF;
END $$;

CREATE INDEX IF NOT EXISTS idx_employees_employee_id ON employees(employee_id);
CREATE INDEX IF NOT EXISTS idx_employees_status ON employees(status);
CREATE INDEX IF NOT EXISTS idx_employees_area_id ON employees(area_id);
CREATE INDEX IF NOT EXISTS idx_employees_franchise_id ON employees(franchise_id);
CREATE INDEX IF NOT EXISTS idx_employees_franchise_id_area_id ON employees(franchise_id, area_id);
CREATE INDEX IF NOT EXISTS idx_employees_created_at ON employees(created_at);
CREATE INDEX IF NOT EXISTS idx_attendance_employee_id ON attendance(employee_id);
CREATE INDEX IF NOT EXISTS idx_attendance_scan_time ON attendance(scan_time);
CREATE INDEX IF NOT EXISTS idx_attendance_scan_source_time ON attendance(scan_source, scan_time DESC);
CREATE INDEX IF NOT EXISTS idx_attendance_employee_scan_time ON attendance(employee_id, scan_time DESC);
CREATE INDEX IF NOT EXISTS idx_audit_logs_user_id ON audit_logs(user_id);
CREATE INDEX IF NOT EXISTS idx_audit_logs_created_at ON audit_logs(created_at);

CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ language 'plpgsql';

DROP TRIGGER IF EXISTS update_users_updated_at ON users;
CREATE TRIGGER update_users_updated_at BEFORE UPDATE ON users
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

DROP TRIGGER IF EXISTS update_employees_updated_at ON employees;
CREATE TRIGGER update_employees_updated_at BEFORE UPDATE ON employees
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

