INSERT INTO employees (employee_id, full_name, supervisor_id, role, address, latitude, longitude, contact_number, franchise_id, area_id, status, radius_meters, municipality_id, photo_url, id_photo_url, coordinate_screenshot_url, qr_code, created_at, updated_at)
SELECT 
    t.employee_id::VARCHAR(50), 
    t.full_name::VARCHAR(255), 
    (SELECT id FROM supervisors WHERE name = t.spvr::VARCHAR(255) LIMIT 1),
    t.role::VARCHAR(100), 
    t.address::TEXT, 
    t.latitude::DECIMAL, 
    t.longitude::DECIMAL, 
    t.contact_number::VARCHAR(50), 
    (SELECT id FROM franchises WHERE name ILIKE t.franchise::VARCHAR(255) LIMIT 1),
    (SELECT id FROM areas WHERE name = t.area::VARCHAR(255) LIMIT 1),
    t.status::VARCHAR(50), 
    t.radius_meters::INTEGER, 
    (SELECT id FROM municipalities WHERE name = t.municipality::VARCHAR(255) LIMIT 1),
    t.photo_url::TEXT, 
    t.id_photo_url::TEXT, 
    t.coordinate_screenshot_url::TEXT, 
    t.qr_code::TEXT, 
    t.created_at::TIMESTAMP WITH TIME ZONE, 
    t.updated_at::TIMESTAMP WITH TIME ZONE
FROM temp_data t
ON CONFLICT (employee_id) DO NOTHING;

